    82	func deleteHealthCheckNodePort(service *corev1api.Service) error {
    83		// Check service type and external traffic policy setting,
    84		// if the setting is not applicable for HealthCheckNodePort, return early.
    85		if service.Spec.ExternalTrafficPolicy != corev1api.ServiceExternalTrafficPolicyTypeLocal ||
    86			service.Spec.Type != corev1api.ServiceTypeLoadBalancer {
    87			return nil
    88		}
    89	
    90		// HealthCheckNodePort is already 0, return.
    91		if service.Spec.HealthCheckNodePort == 0 {
    92			return nil
    93		}
    94	
    95		// Search HealthCheckNodePort from server's last-applied-configuration
    96		// annotation(HealthCheckNodePort is specified by `kubectl apply` command)
    97		lastAppliedConfig, ok := service.Annotations[annotationLastAppliedConfig]
    98		if ok {
    99			appliedServiceUnstructured := new(map[string]any)
   100			if err := json.Unmarshal([]byte(lastAppliedConfig), appliedServiceUnstructured); err != nil {
   101				return errors.WithStack(err)
   102			}
   103	
   104			healthCheckNodePort, exist, err := unstructured.NestedFloat64(*appliedServiceUnstructured, "spec", "healthCheckNodePort")
   105			if err != nil {
   106				return errors.WithStack(err)
   107			}
   108	
   109			// Found healthCheckNodePort in lastAppliedConfig annotation,
   110			// and the value is not 0. No need to delete, return.
   111			if exist && healthCheckNodePort != 0 {
   112				return nil
   113			}
   114		}
   115	
   116		// Search HealthCheckNodePort from ManagedFields(HealthCheckNodePort
   117		// is specified by `kubectl apply --server-side` command).
   118		for _, entry := range service.GetManagedFields() {
   119			if entry.FieldsV1 == nil {
   120				continue
   121			}
   122			fields := new(map[string]any)
   123			if err := json.Unmarshal(entry.FieldsV1.Raw, fields); err != nil {
   124				return errors.WithStack(err)
   125			}
   126	
   127			_, exist, err := unstructured.NestedMap(*fields, "f:spec", "f:healthCheckNodePort")
   128			if err != nil {
   129				return errors.WithStack(err)
   130			}
   131			if !exist {
   132				continue
   133			}
   134			// Because the format in ManagedFields is `f:healthCheckNodePort: {}`,
   135			// cannot get the value, check whether exists is enough.
   136			// Found healthCheckNodePort in ManagedFields.
   137			// No need to delete. Return.
   138			return nil
   139		}
   140	
   141		// Cannot find HealthCheckNodePort from Annotation and
   142		// ManagedFields, which means it's auto-generated. Delete it.
   143		service.Spec.HealthCheckNodePort = 0
   144	
   145		return nil
   146	}
