    "github.com/vmware-tanzu/velero/pkg/plugin/velero"
    "github.com/vmware-tanzu/velero/pkg/restore/actions"
    velerotest "github.com/vmware-tanzu/velero/pkg/test"
)

type scenario struct {
    name        string
    annotation  string
    managedRaw  string
    wantPort    int32
    wantErrText string
}

func run(s scenario) error {
    service := corev1api.Service{}
    service.Name = "trap-listener-udp-load-balancer"
    service.Namespace = "xxx"
    if s.annotation != "" {
        service.Annotations = map[string]string{
            "kubectl.kubernetes.io/last-applied-configuration": s.annotation,
        }
    }
    if s.managedRaw != "" {
        service.ManagedFields = []metav1.ManagedFieldsEntry{{FieldsV1: &metav1.FieldsV1{Raw: []byte(s.managedRaw)}}}
    }
    service.Spec.Type = corev1api.ServiceTypeLoadBalancer
    service.Spec.ExternalTrafficPolicy = corev1api.ServiceExternalTrafficPolicyTypeLocal
    service.Spec.HealthCheckNodePort = 31743
    service.Spec.Ports = []corev1api.ServicePort{{Name: "162-udp", Port: 162, Protocol: corev1api.ProtocolUDP}}

    obj, err := runtime.DefaultUnstructuredConverter.ToUnstructured(&service)
    if err != nil {
        return fmt.Errorf("convert input: %w", err)
    }

    out, err := actions.NewServiceAction(velerotest.NewLogger()).Execute(&velero.RestoreItemActionExecuteInput{
        Item:           &unstructured.Unstructured{Object: obj},
        ItemFromBackup: &unstructured.Unstructured{Object: obj},
        Restore:        &api.Restore{},
    })
    if s.wantErrText != "" {
        if err == nil || !strings.Contains(err.Error(), s.wantErrText) {
            return fmt.Errorf("expected error containing %q, got %v", s.wantErrText, err)
        }
        fmt.Printf("OK %-36s expected error: %v\n", s.name, err)
        return nil
    }
    if err != nil {
        return fmt.Errorf("unexpected error: %w", err)
    }

    var got corev1api.Service
    if err := runtime.DefaultUnstructuredConverter.FromUnstructured(out.UpdatedItem.UnstructuredContent(), &got); err != nil {
        return fmt.Errorf("convert output: %w", err)
    }
    if got.Spec.HealthCheckNodePort != s.wantPort {
        return fmt.Errorf("healthCheckNodePort=%d, want %d", got.Spec.HealthCheckNodePort, s.wantPort)
    }
    fmt.Printf("OK %-36s healthCheckNodePort=%d\n", s.name, got.Spec.HealthCheckNodePort)
    return nil
}

func main() {
    scenarios := []scenario{
        {
            name:       "null in last-applied clears",
            annotation: `{"apiVersion":"v1","kind":"Service","spec":{"externalTrafficPolicy":"Local","healthCheckNodePort":null,"ports":[{"name":"162-udp","port":162,"protocol":"UDP"}],"type":"LoadBalancer"}}`,
            wantPort:   0,
        },
        {
            name:       "missing in last-applied clears",
            annotation: `{"apiVersion":"v1","kind":"Service","spec":{"externalTrafficPolicy":"Local","ports":[{"name":"162-udp","port":162,"protocol":"UDP"}],"type":"LoadBalancer"}}`,
            wantPort:   0,
        },
        {
            name:       "zero in last-applied clears",
            annotation: `{"apiVersion":"v1","kind":"Service","spec":{"externalTrafficPolicy":"Local","healthCheckNodePort":0,"ports":[{"name":"162-udp","port":162,"protocol":"UDP"}],"type":"LoadBalancer"}}`,
            wantPort:   0,
        },
        {
            name:       "number in last-applied preserves",
            annotation: `{"apiVersion":"v1","kind":"Service","spec":{"externalTrafficPolicy":"Local","healthCheckNodePort":31743,"ports":[{"name":"162-udp","port":162,"protocol":"UDP"}],"type":"LoadBalancer"}}`,
            wantPort:   31743,
        },
        {
            name:       "managedFields preserves after null",
            annotation: `{"apiVersion":"v1","kind":"Service","spec":{"healthCheckNodePort":null}}`,
            managedRaw: `{"f:spec":{"f:healthCheckNodePort":{}}}`,
            wantPort:   31743,
        },
        {
            name:        "string remains invalid",
            annotation:  `{"apiVersion":"v1","kind":"Service","spec":{"healthCheckNodePort":"31743"}}`,
            wantErrText: "expected float64",
        },
    }

    for _, s := range scenarios {
        if err := run(s); err != nil {
            fmt.Printf("FAIL %s: %v\n", s.name, err)
            os.Exit(1)
        }
    }
}
